import React, { useState, useEffect } from 'react';
import { Download, FileText, RefreshCw, Filter } from 'lucide-react';
import { DataTable } from '../../components/ui/DataTable';
import { Button } from '../../components/common/Button';
import { getPosts, getDistricts } from '../../services/master.service';
import { getMeritList, generateMeritList, exportMeritList, selectApplication } from '../../services/admin.service';
import toast from 'react-hot-toast';

const MeritList = () => {
    const [meritList, setMeritList] = useState([]);
    const [posts, setPosts] = useState([]);
    const [districts, setDistricts] = useState([]);
    const [loading, setLoading] = useState(false);
    const [batchInfo, setBatchInfo] = useState(null);

    // Filters
    const [selectedPost, setSelectedPost] = useState('');
    const [selectedDistrict, setSelectedDistrict] = useState('');

    // Pagination
    const [page, setPage] = useState(1);
    const [limit, setLimit] = useState(20);

    useEffect(() => {
        const loadMasters = async () => {
            try {
                const [postsRes, districtsRes] = await Promise.all([
                    getPosts({ is_active: true }),
                    getDistricts({ is_active: true })
                ]);
                setPosts(Array.isArray(postsRes) ? postsRes : postsRes.posts || []);
                setDistricts(Array.isArray(districtsRes) ? districtsRes : districtsRes.districts || []);
            } catch (err) {
                console.error('Failed to load masters', err);
            }
        };
        loadMasters();
    }, []);

    const fetchList = async () => {
        if (!selectedPost) return;

        setLoading(true);
        try {
            const data = await getMeritList(selectedPost, selectedDistrict || null);
            setMeritList(Array.isArray(data) ? data : data.meritList || []);
            setBatchInfo(data.batchInfo || null);
        } catch (error) {
            console.error('Fetch merit list error', error);
            setBatchInfo(null);
            // toast.error('Failed to fetch merit list');
        } finally {
            setLoading(false);
        }
    };

    // Auto-fetch when filters change (if post is selected)
    useEffect(() => {
        if (selectedPost) {
            fetchList();
        } else {
            setMeritList([]);
        }
    }, [selectedPost, selectedDistrict]);

    const handleGenerate = async () => {
        if (!selectedPost) {
            return toast.error('Please select a post first');
        }

        if (!window.confirm('This will recalculate scores for all eligible candidates. Do you want to proceed?')) {
            return;
        }

        const toastId = toast.loading('Generating merit list...');
        try {
            await generateMeritList(selectedPost, selectedDistrict || null);
            toast.success('Merit list generated successfully', { id: toastId });
            fetchList();
        } catch (error) {
            toast.error('Failed to generate merit list', { id: toastId });
        }
    };

    const handleExport = async (format) => {
        if (!selectedPost) return toast.error('Select a post to export');

        try {
            const blob = await exportMeritList(selectedPost, format, selectedDistrict || null);
            // Handle blob download (requires backend to return blob/file)
            // For now assuming the service returns data url or similar, or browser handles it if window.open
            toast.success(`Exporting as ${format.toUpperCase()}...`);
        } catch (error) {
            toast.error('Export failed');
        }
    };

    const handleSelect = async (applicationId) => {
        if (!window.confirm('Mark this candidate as SELECTED? This will auto-reject their other applications.')) {
            return;
        }
        const toastId = toast.loading('Selecting candidate...');
        try {
            const result = await selectApplication(applicationId);
            toast.success(`Selected! ${result?.autoRejectedCount || 0} other applications auto-rejected.`, { id: toastId });
            fetchList();
        } catch (error) {
            toast.error(error.message || 'Selection failed', { id: toastId });
        }
    };

    const columns = [
        { key: 'rank', header: 'Rank', width: '60px' },
        {
            key: 'application_no',
            header: 'App No',
            render: (row) => row.application?.application_no
        },
        {
            key: 'applicant_name',
            header: 'Applicant Name',
            render: (row) => row.application?.applicant?.personal?.full_name
        },
        {
            key: 'is_local',
            header: 'Local',
            width: '60px',
            render: (row) => row.is_local_candidate ? 
                <span className="text-green-600 font-medium">Yes</span> : 
                <span className="text-slate-400">No</span>
        },
        {
            key: 'education_score',
            header: 'Edu',
            width: '60px',
            render: (row) => <span className="text-xs">{row.education_score || 0}</span>
        },
        {
            key: 'marks_score',
            header: 'Marks',
            width: '60px',
            render: (row) => <span className="text-xs">{row.marks_score || 0}</span>
        },
        {
            key: 'experience_score',
            header: 'Exp',
            width: '60px',
            render: (row) => <span className="text-xs">{row.experience_score || 0}</span>
        },
        {
            key: 'age_score',
            header: 'Age',
            width: '60px',
            render: (row) => <span className="text-xs">{row.age_score || 0}</span>
        },
        {
            key: 'local_preference_score',
            header: 'Local',
            width: '60px',
            render: (row) => <span className="text-xs">{row.local_preference_score || 0}</span>
        },
        {
            key: 'score',
            header: 'Total',
            width: '70px',
            render: (row) => <span className="font-bold text-blue-600">{row.score}</span>
        },
        {
            key: 'status',
            header: 'Status',
            width: '100px',
            render: (row) => {
                const status = row.selection_status || 'PENDING';
                const colors = {
                    PENDING: 'bg-slate-100 text-slate-600',
                    SELECTED: 'bg-green-100 text-green-700',
                    REJECTED: 'bg-red-100 text-red-700',
                    SELECTED_IN_OTHER_POST: 'bg-yellow-100 text-yellow-700'
                };
                return <span className={`px-2 py-1 rounded text-xs ${colors[status] || colors.PENDING}`}>{status}</span>;
            }
        },
        {
            key: 'actions',
            header: 'Actions',
            width: '100px',
            render: (row) => row.selection_status === 'PENDING' ? (
                <Button
                    size="sm"
                    variant="primary"
                    onClick={() => handleSelect(row.application_id)}
                >
                    Select
                </Button>
            ) : null
        }
    ];

    return (
        <div className="space-y-6">
            <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
                <div>
                    <h1 className="text-2xl font-bold text-slate-900">Merit List</h1>
                    <p className="text-sm text-slate-500 mt-1">Generate and view merit lists</p>
                </div>
                <div className="flex gap-2">
                    <Button
                        variant="primary"
                        onClick={handleGenerate}
                        disabled={!selectedPost}
                        leftIcon={<RefreshCw className="h-4 w-4" />}
                    >
                        Generate List
                    </Button>
                    <Button
                        variant="outline"
                        onClick={() => handleExport('excel')}
                        disabled={!selectedPost || meritList.length === 0}
                        leftIcon={<FileText className="h-4 w-4" />}
                    >
                        Export Excel
                    </Button>
                </div>
            </div>

            <div className="bg-white p-4 rounded-lg shadow border">
                <div className="grid grid-cols-1 md:grid-cols-3 gap-4 items-end">
                    <div>
                        <label className="block text-sm font-medium mb-1">Post <span className="text-red-500">*</span></label>
                        <select
                            value={selectedPost}
                            onChange={(e) => setSelectedPost(e.target.value)}
                            className="w-full rounded-md border px-3 py-2 text-sm"
                        >
                            <option value="">Select Post</option>
                            {posts.map(p => <option key={p.post_id} value={p.post_id}>{p.post_name}</option>)}
                        </select>
                    </div>
                    <div>
                        <label className="block text-sm font-medium mb-1">District (Optional)</label>
                        <select
                            value={selectedDistrict}
                            onChange={(e) => setSelectedDistrict(e.target.value)}
                            className="w-full rounded-md border px-3 py-2 text-sm"
                        >
                            <option value="">All Districts</option>
                            {districts.map(d => <option key={d.district_id} value={d.district_id}>{d.district_name}</option>)}
                        </select>
                    </div>
                    <div>
                        {/* Placeholder for spacing */}
                    </div>
                </div>
            </div>

            {/* Batch Info Display */}
            {batchInfo && (
                <div className={`p-4 rounded-lg border ${
                    batchInfo.is_filtered 
                        ? 'bg-blue-50 border-blue-200' 
                        : 'bg-slate-50 border-slate-200'
                }`}>
                    <div className="flex items-center justify-between">
                        <div>
                            <h3 className={`font-semibold ${
                                batchInfo.is_filtered ? 'text-blue-900' : 'text-slate-900'
                            }`}>
                                {batchInfo.is_filtered ? 'Your Assigned Batch' : 'No Batch Assignment'}
                            </h3>
                            {batchInfo.is_filtered ? (
                                <p className="text-sm text-blue-700 mt-1">
                                    You are reviewing ranks <strong>{batchInfo.batch_start}</strong> to <strong>{batchInfo.batch_end}</strong>
                                    {' '}({batchInfo.batch_size} applicants total)
                                </p>
                            ) : (
                                <p className="text-sm text-slate-600 mt-1">
                                    You can see all applicants. Contact admin to assign a batch.
                                </p>
                            )}
                        </div>
                        {batchInfo.note && (
                            <div className="text-xs text-slate-500 italic">
                                {batchInfo.note}
                            </div>
                        )}
                    </div>
                </div>
            )}

            {selectedPost ? (
                <DataTable
                    columns={columns}
                    data={meritList}
                    pagination={{
                        currentPage: page,
                        totalPages: Math.ceil(meritList.length / limit) || 1,
                        onPageChange: setPage,
                        pageSize: limit,
                        onPageSizeChange: setLimit
                    }}
                    isLoading={loading}
                    rowKey="merit_id"
                />
            ) : (
                <div className="text-center py-10 bg-slate-50 border border-dashed rounded-lg">
                    <Filter className="h-10 w-10 text-slate-300 mx-auto mb-2" />
                    <p className="text-slate-500">Please select a post to view the merit list</p>
                </div>
            )}
        </div>
    );
};

export default MeritList;
